func formTitle(c *domain.Customer) string {
	if c == nil {
		return "New Customer"
	}
	return "Edit " + c.CompanyName
}

func formSubtitle(c *domain.Customer) string {
	if c == nil {
		return "Add a new customer"
	}
	return "Update customer details"
}

func formSignals(c *domain.Customer) string {
	type sig struct {
		CompanyName string `json:"companyName"`
		ContactName string `json:"contactName"`
		Email       string `json:"email"`
		Phone       string `json:"phone"`
		Street      string `json:"street"`
		City        string `json:"city"`
		PostalCode  string `json:"postalCode"`
		Country     string `json:"country"`
		TaxID       string `json:"taxId"`
		Notes       string `json:"notes"`
		RouterID    string `json:"routerId"`
		NetworkZone string `json:"networkZone"`
		IPAddress   string `json:"ipAddress"`
		MACAddress  string `json:"macAddress"`
	}
	if c == nil {
		b, _ := json.Marshal(sig{})
		return string(b)
	}
	routerID := ""
	if c.RouterID != nil {
		routerID = *c.RouterID
	}
	b, _ := json.Marshal(sig{
		CompanyName: c.CompanyName,
		ContactName: c.ContactName,
		Email:       c.Email,
		Phone:       c.Phone,
		Street:      c.Street,
		City:        c.City,
		PostalCode:  c.PostalCode,
		Country:     c.Country,
		TaxID:       c.TaxID,
		Notes:       c.Notes,
		RouterID:    routerID,
		NetworkZone: c.NetworkZone,
		IPAddress:   c.IPAddress,
		MACAddress:  c.MACAddress,
	})
	return string(b)
}

func formAction(c *domain.Customer) string {
	if c == nil {
		return "@post('/api/customers')"
	}
	return fmt.Sprintf("@put('/api/customers/%s')", c.ID)
}

func formButtonText(c *domain.Customer) string {
	if c == nil {
		return "Create Customer"
	}
	return "Save Changes"
}

